grep -E '/api/v[0-9]+/internal/' /var/log/app/access.log | grep -v '^10\.' | awk '{
  # Extract timestamp from brackets
  match($0, /\[([^\]]+)\]/, ts);
  timestamp = ts[1];

  # Parse: DD/Mon/YYYY:HH:MM:SS +ZONE
  split(timestamp, dt, /[\/:]/); 
  day = dt[1];
  month = dt[2];
  year = dt[3];
  time = dt[4] ":" dt[5] ":" dt[6];

  # Convert month name to number
  months["Jan"]="01"; months["Feb"]="02"; months["Mar"]="03"; months["Apr"]="04";
  months["May"]="05"; months["Jun"]="06"; months["Jul"]="07"; months["Aug"]="08";
  months["Sep"]="09"; months["Oct"]="10"; months["Nov"]="11"; months["Dec"]="12";

  iso_date = year "-" months[month] "-" day "T" time;

  # Replace timestamp in original line
  sub(/\[[^\]]+\]/, iso_date);
  print;
}' > /home/user/internal_hits.log

